var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"정면은 전부 처리했어요! 오른쪽에서 펜듈럼 반응! 더 옵니다!","JPN":"正面はすべて片付けました！　右から振り子の反応が！　また来ます！","ENG":"We've cleared the front! Pendulum reaction on the right! More incoming!","TWN":"正面都清完了！右側有鐘擺反應！又有更多過來了！"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"발자국 발견했어요. 제가 처리하죠.","JPN":"足跡を見つけました。僕がやります。","ENG":"I found footprints. I'll handle it.","TWN":"發現腳印，我去處理。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아직 반응하고 있어요! 하나 더...!","JPN":"まだ反応があります！　もう1体……！","ENG":"It's still reacting! One more...!","TWN":"還有反應！又一個……！"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"네? 하지만 발자국은 이제 안 보이는...","JPN":"え？　ですが、足跡はもう見当たらな……","ENG":"Huh? But the footprints just disappeared...","TWN":"咦？可是腳印已經不見了……"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"...찾았다!","JPN":"……あった！","ENG":"...Found it!","TWN":"……找到了！"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"오.","JPN":"お。","ENG":"Oh.","TWN":"喔。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"휴우...","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"이 녀석, 발자국 안 남기려고 인형들을 밟으면서 왔어요.","JPN":"こいつ、足跡を残さないために他の人形を踏みながら移動してきました。","ENG":"This one stepped on the puppets as it came so it wouldn't leave footprints.","TWN":"這傢伙為了不留下腳印，踩著人偶過來的。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"굉장하네. 그걸 소리로 알아챈 거야? 난 아무것도 안 들렸는데.","JPN":"すごい。音でそれが分かったの？　私は何も聞こえなかったけど。","ENG":"That's impressive. You figured that out just from the sound? I didn't hear anything.","TWN":"真厲害，你是靠聲音發現的嗎？我什麼都沒聽到。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"하하...","JPN":"はは……","ENG":"Haha...","TWN":"哈哈……"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"펜듈럼 반응 없음. 이 근방은 전부 처리됐네요.","JPN":"振り子の反応無し。この辺はすべて片付けましたね。","ENG":"No pendulum reaction. Everything around here's been cleared.","TWN":"沒有鐘擺反應了，這一帶全清乾淨了。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다들 고생 많았네. 벌써 산 중턱까지 올라왔어.","JPN":"皆ご苦労だった。もう山の中腹だ。","ENG":"Good work, everyone. We've already made it halfway up the mountain.","TWN":"大家辛苦了，我們已經爬到山腰了。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"총사대장님의 열쇠와 프라이머 양의 펜듈럼 덕분이죠.","JPN":"銃士隊長の鍵と、プライマーさんの振り子のおかげです。","ENG":"Thanks to General Musketeer's Key and Nicole Primer's pendulum.","TWN":"多虧隊長的鑰匙，還有布萊伊莫小姐的鐘擺。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"하지만, 위로 올라갈수록 인형 녀석들의 저항이 거세지고 있어.","JPN":"しかし、上に近づくほど人形の抵抗が激しくなっている。","ENG":"But the higher we go, the fiercer the dolls' resistance is getting.","TWN":"不過越往上，人偶的抵抗越激烈。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"제 시간에 도착하긴 무리일 거다.","JPN":"これでは間に合わない。","ENG":"We won't make it in time at this rate.","TWN":"看來很難準時抵達了。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 말이 맞아. 황금나무의 영향으로 우리의 존재는 지금도 조금씩 옅어지고 있지.","JPN":"そうだな。黄金の木の影響で私たちの存在は今も少しずつ薄くなっている。","ENG":"She's right. The Golden Tree's influence is gradually fading our existence even now.","TWN":"沒錯。在黃金樹的影響下，現在我們的存在也逐漸消失。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 속도라면 정상에 도달하기도 전에 우리가 먼저 사라지고 말 거야.","JPN":"このスピードだと、頂上に辿り着くより先に私たちが消えてしまうだろう。","ENG":"At this pace, we'll disappear before we even reach the summit.","TWN":"照這速度，還沒到山頂，我們就會先消失。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"좀 더 빨리 갈 수 있는 방법은 없을까요?","JPN":"もっと早く行ける方法はないでしょうか？","ENG":"Isn't there any way we can move faster?","TWN":"有沒有更快的方法？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"함선은 물론, 허밋 같은 병기마 역시 신성 때문에 동력을 억제 당하고 있는 상황일세.","JPN":"艦船はもちろん、ハーミットのような兵器馬も神聖のせいで動力を制限されている。","ENG":"Even the ship and an Armored Horse like Hermit are having their power suppressed by the Divinity.","TWN":"不只是艦船，就連像赫米特那樣的戰馬，也因為神性影響而被壓制動力。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"우리 모두가 인형을 따돌리고 빠른 시간에 정상에 다다를 묘책은 없어 보이는군.","JPN":"全員が人形を撒いて短時間で頂上にたどり着く妙策はなさそうだ。","ENG":"It doesn't look like there's any good way for all of us to shake off the dolls and reach the summit quickly.","TWN":"看來沒有什麼辦法能讓我們同時擺脫人偶又快速登頂。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"혹시 모르니, 흩어져서 지름길을 찾아보는 것 정도는...","JPN":"念のため、手分けして近道を探すくらいなら……","ENG":"If anything, maybe splitting up to look for a shortcut–","TWN":"不然，我們分頭找捷徑看看？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지휘관! 뒤에!","JPN":"指揮官！　後ろだ！","ENG":"Commander! Behind you!","TWN":"指揮官！後面！"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이런.","JPN":"おっと。","ENG":"Dammit.","TWN":"糟了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아직 움직이는 침식체가 남아있는 줄은 몰랐군.","JPN":"まだ動いている侵食体がいたとは。","ENG":"I didn't realize there was still a C.O.","TWN":"沒想到還有在活動的侵蝕體。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"처리해줘서 고맙네, 중사.","JPN":"礼を言う、軍曹。","ENG":"Thanks for taking care of it, Sergeant.","TWN":"幹得好，中士，謝了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"대단하네. 탄환이 만든 바람에 지휘관이 휘말려서 날아갈 뻔했어.","JPN":"すごいな。引き金を引いただけなのに、指揮官が余波に巻き込まれて飛ばされるところだった。","ENG":"Impressive. You pulled the trigger once and nearly blew Commander away with the aftershock.","TWN":"真厲害。只是扣了一次扳機，指揮官就差點被捲入後座力飛出去了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지금 지휘관이 허밋에 깔렸는데 감탄이나 하고 있을 때야?!","JPN":"指揮官がハーミットに下敷きになってるのに、感心してる場合じゃないでしょう！？","ENG":"Now's not the time to be impressed when Commander just got pinned under Hermit?!","TWN":"現在指揮官還被赫米特壓著，你竟然在感嘆？！"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};